import QtQml
import QtQuick
import QtQuick3D
import "common" as Common
import "common/Logger.js" as Logger

Item {
    id: root

    // レイヤーの表示状態を取得する関数（外部から注入される）
    property var getLayerVisible: function(layer) {
        return true;
    }
    // 外部から注入可能なプロパティ (デフォルトはTimelineBridgeから取得)
    property var clipModel: TimelineBridge ? TimelineBridge.clipModel : null
    property int projectWidth: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.width : 1920
    property int projectHeight: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.height : 1080
    property int currentFrame: (TimelineBridge && TimelineBridge.transport) ? TimelineBridge.transport.currentFrame : 0
    readonly property int hiddenZ: -9999
    // Component cache to prevent redundant Qt.createComponent calls
    property var _componentCache: ({
    })
    property bool exportMode: false
    property alias view3D: view
    // ─── グループ制御管理 ─────────────────────────────────────────
    property var groupControls: []
    // ─── カメラ制御管理 ─────────────────────────────────────────
    property var activeCameraControl: null

    function registerCameraControl(cc) {
        activeCameraControl = cc;
    }

    function unregisterCameraControl(cc) {
        if (activeCameraControl === cc)
            activeCameraControl = null;

    }

    function getCachedComponent(url) {
        if (_componentCache[url])
            return _componentCache[url];

        var c = Qt.createComponent(url, Component.Asynchronous);
        _componentCache[url] = c;
        return c;
    }

    function registerGroupControl(gc) {
        for (var i = 0; i < groupControls.length; ++i) {
            if (groupControls[i] === gc)
                return ;

        }
        groupControls.push(gc);
        groupControlsChanged(); // 配列変更を通知して再計算を促す
    }

    function unregisterGroupControl(gc) {
        var idx = -1;
        for (var i = 0; i < groupControls.length; ++i) {
            if (groupControls[i] === gc) {
                idx = i;
                break;
            }
        }
        if (idx !== -1) {
            groupControls.splice(idx, 1);
            groupControlsChanged();
        }
    }

    // 2Dレンダー（sourceItem/effects/ShaderEffectSource）を必ずQQuickWindow配下に置くためのホスト
    // visible:false でもWindow配下に居ればSceneGraph/Timerが正常に動く
    Item {
        id: offscreenRenderHost

        anchors.fill: parent
        visible: true
        opacity: 0
        enabled: false
        z: hiddenZ
    }

    // 背景
    Rectangle {
        anchors.fill: parent
        color: "transparent"
        z: -2
    }

    // プレビューコンテナ
    View3D {
        id: view

        // プロジェクト設定の解像度を取得
        property int projW: root.projectWidth
        property int projH: root.projectHeight
        // アスペクト比計算
        property double aspect: projW / projH
        // 現在のクリップ内での相対時間 (0.0 ~ 1.0)
        property double currentClipTimeRatio: (TimelineBridge) ? Math.max(0, Math.min(1, (root.currentFrame - TimelineBridge.clipStartFrame) / TimelineBridge.clipDurationFrames)) : 0

        camera: activeCameraControl ? activeCameraControl.camera : mainCamera
        // 親に収まる最大サイズを計算 (Letterboxing)
        width: root.exportMode ? projW : Math.min(parent.width, parent.height * aspect)
        height: root.exportMode ? projH : Math.min(parent.height, parent.width / aspect)
        anchors.centerIn: parent
        focus: true
        Keys.onSpacePressed: {
            if (TimelineBridge && TimelineBridge.transport)
                TimelineBridge.transport.togglePlay();

        }

        // プロジェクト領域の背景
        Rectangle {
            anchors.fill: parent
            color: "#0a0a0a"
            z: -1
        }

        // カメラ設定
        PerspectiveCamera {
            id: mainCamera

            property real distance: view.projH / (2 * Math.tan(fieldOfView * Math.PI / 360))

            // 動的カメラ距離計算: projH/2 / tan(fieldOfView/2)
            fieldOfView: 30
            position: Qt.vector3d(0, 0, distance)
            clipFar: 5000
        }

        DirectionalLight {
            eulerRotation.x: -30
            z: 1000
        }

        // プロジェクトの枠線（解像度ガイド）
        Node {
            // 画面中央を (0,0) としたときの枠
            Model {
                source: "#Rectangle"
                scale: Qt.vector3d(root.projectWidth / 100, root.projectHeight / 100, 1)
                position: Qt.vector3d(0, 0, -10)
                visible: false // 邪魔なので一旦隠す

                materials: DefaultMaterial {
                    diffuseColor: "#22000000"
                }
                // 奥に配置

            }

        }

        // Instantiator の親となるノード
        Node {
            id: sceneRoot
        }

        // 動的オブジェクト生成用
        Instantiator {
            // 拡大率は親の影響を受けず自身のサイズとして適用（AviUtl仕様依存）

            model: root.clipModel
            onObjectAdded: (index, object) => {
                object.parent = sceneRoot;
            }
            onObjectRemoved: (index, object) => {
                object.parent = null;
            }

            delegate: Node {
                id: clipNode

                // C++モデル(model)とJS配列(modelData)の両方に対応
                property var _clipData: (typeof modelData !== "undefined") ? modelData : model
                // FB 収集用: BaseObject が参照できるよう layer を公開
                property int clipLayerRole: _clipData.layer
                property Item fbRendererOutput: null // NodeLoader 完了後に接続
                // モデルロールから直接値を取得
                // パラメータを一度だけ取得してキャッシュ
                readonly property var p: _clipData.params || {
                }
                readonly property real px: p.x || 0
                readonly property real py: p.y || 0
                readonly property real pz: p.z || 0
                readonly property real pRotX: p.rotationX || 0
                readonly property real pRotY: p.rotationY || 0
                readonly property real pRotZ: p.rotationZ || 0
                readonly property real pScale: p.scale || 100
                readonly property real pAspect: p.aspect || 0
                readonly property real pOpacity: p.opacity || 1
                // 拡大率と縦横比
                readonly property real baseScale: pScale * 0.01
                readonly property real aspectX: pAspect >= 0 ? (1 + pAspect) : 1
                readonly property real aspectY: pAspect < 0 ? (1 - pAspect) : 1
                // ─── 実効トランスフォーム計算 (グループ制御適用) ───────────
                property var effectiveTransform: {
                    // 依存関係を明示的に登録 (groupControlsの変更を検知)
                    var _gcList = root.groupControls;
                    // 1. 適用可能なグループ制御を抽出
                    var activeGroups = [];
                    for (var i = 0; i < root.groupControls.length; ++i) {
                        var gc = root.groupControls[i];
                        if (!gc)
                            continue;

                        if (gc.clipLayer < _clipData.layer && _clipData.layer <= (gc.clipLayer + gc.layerCount))
                            activeGroups.push(gc);

                    }
                    // 2. レイヤー順（親→子）にソート
                    // 上位レイヤー(数値が小さい)ほど親として振る舞う
                    activeGroups.sort(function(a, b) {
                        return a.clipLayer - b.clipLayer;
                    });
                    // 3. 行列による階層的な座標計算
                    // グローバル座標系での変換行列を作成
                    var m = Qt.matrix4x4();
                    var totalOpacity = pOpacity;
                    var totalRotX = 0;
                    var totalRotY = 0;
                    var totalRotZ = 0;
                    // 親グループから順に変換を適用
                    for (var j = 0; j < activeGroups.length; ++j) {
                        var g = activeGroups[j];
                        // AviUtl互換座標系 (Y下プラス) で計算するため、Y軸反転などは最終出力時に行う
                        m.translate(Qt.vector3d(g.x, g.y, g.z));
                        m.rotate(g.rotationX, Qt.vector3d(1, 0, 0));
                        m.rotate(g.rotationY, Qt.vector3d(0, 1, 0));
                        m.rotate(g.rotationZ, Qt.vector3d(0, 0, 1));
                        var s = g.scale / 100;
                        m.scale(s, s, s);
                        totalOpacity *= g.opacity;
                        // 回転の単純加算（近似値。厳密な3D回転合成ではないが、AviUtl的な挙動としては十分）
                        totalRotX += g.rotationX;
                        totalRotY += g.rotationY;
                        totalRotZ += g.rotationZ;
                    }
                    // 最後にオブジェクト自身のローカル座標を適用
                    m.translate(Qt.vector3d(px, py, pz));
                    // 行列から最終的な位置を取得 (translation vector)
                    // column(3) は平行移動成分 (x, y, z, w)
                    var pos = m.column(3);
                    var t = {
                        "x": pos.x,
                        "y": pos.y,
                        "z": pos.z,
                        "rx": pRotX + totalRotX,
                        "ry": pRotY + totalRotY,
                        "rz": pRotZ + totalRotZ,
                        "sx": baseScale * aspectX,
                        "sy": baseScale * aspectY,
                        "sz": baseScale,
                        "opacity": totalOpacity
                    };
                    return t;
                }

                function dbg(msg) {
                    Logger.log("[CompositeView][clipId=" + _clipData.id + "][type=" + _clipData.type + "] " + msg, TimelineBridge);
                }

                // レイヤーが非表示の場合は描画しない
                visible: {
                    return root.getLayerVisible(_clipData.layer);
                }
                // 座標変換: 中心(0,0)、Y軸下プラス(AviUtl互換)
                // Qt3DはY上がプラスなので、入力を反転させる
                x: effectiveTransform.x
                y: -effectiveTransform.y
                z: effectiveTransform.z + (_clipData.layer * 5)
                // 中心座標 (Pivot)
                pivot: Qt.vector3d(p.anchorX || 0, -(p.anchorY || 0), p.anchorZ || 0)
                // 3軸回転
                eulerRotation.x: effectiveTransform.rx
                eulerRotation.y: -effectiveTransform.ry
                eulerRotation.z: -effectiveTransform.rz
                scale.x: effectiveTransform.sx
                scale.y: effectiveTransform.sy
                scale.z: effectiveTransform.sz
                // 不透明度 (全体)
                opacity: effectiveTransform.opacity
                // params 変化 (scale/pos/rot/opacity) → BaseObject の fbCaptureItem を同期
                onPxChanged: objectContainer._syncTransformToItem()
                onPyChanged: objectContainer._syncTransformToItem()
                onPRotZChanged: objectContainer._syncTransformToItem()
                onBaseScaleChanged: objectContainer._syncTransformToItem()
                onAspectXChanged: objectContainer._syncTransformToItem()
                onAspectYChanged: objectContainer._syncTransformToItem()
                onPOpacityChanged: objectContainer._syncTransformToItem()

                // Loader (2D) は 3D シーン内では機能しないため、
                // Qt.createComponent を使用して Node 派生クラスを動的に生成する
                Common.NodeLoader {
                    id: objectContainer

                    // clipNode の transform が変わるたびに BaseObject へ同期
                    function _syncTransformToItem() {
                        if (!item)
                            return ;

                        if ("clipNodeScaleX" in item)
                            item.clipNodeScaleX = clipNode.baseScale * clipNode.aspectX;

                        if ("clipNodeScaleY" in item)
                            item.clipNodeScaleY = clipNode.baseScale * clipNode.aspectY;

                        if ("clipNodePosX" in item)
                            item.clipNodePosX = clipNode.px;

                        if ("clipNodePosY" in item)
                            item.clipNodePosY = clipNode.py;

                        if ("clipNodeRotZ" in item)
                            item.clipNodeRotZ = clipNode.pRotZ;

                        if ("clipNodeOpacity" in item)
                            item.clipNodeOpacity = clipNode.pOpacity;

                    }

                    source: _clipData.qmlSource || ""
                    properties: {
                        "opacity": clipNode.pOpacity,
                        "clipId": _clipData.id,
                        "clipStartFrame": _clipData.startFrame,
                        "clipDurationFrames": _clipData.durationFrames,
                        "renderHost": offscreenRenderHost,
                        "clipParams": Qt.binding(function() {
                            return _clipData.params || {
                            };
                        })
                    }
                    componentFactory: root.getCachedComponent
                    // NodeLoader 完了後に fbRendererOutput を clipNode へ接続
                    onItemChanged: {
                        // FB専用プロパティは FrameBufferObject にのみ注入
                        if (item) {
                            // fbCaptureItem は BaseObject の property alias として公開済み
                            clipNode.fbRendererOutput = item.fbCaptureItem ?? null;
                            // clipLayer と sceneRootRef は FB のみが持つプロパティ
                            if (typeof item.clipLayer !== "undefined")
                                item.clipLayer = _clipData.layer;

                            if (typeof item.sceneRootRef !== "undefined")
                                item.sceneRootRef = sceneRoot;

                            // レイヤー番号を注入 (グループ制御判定用)
                            if ("clipLayer" in item)
                                item.clipLayer = _clipData.layer;

                            // グループ制御オブジェクトなら登録
                            if (item.isGroupControl && root.registerGroupControl)
                                root.registerGroupControl(item);

                            // カメラ制御オブジェクトなら登録
                            if (item.isCameraControl && root.registerCameraControl)
                                root.registerCameraControl(item);

                            // 変換パラメータを注入 (初期値)
                            _syncTransformToItem();
                        }
                    }
                }

            }

        }

        environment: SceneEnvironment {
            id: sceneEnv

            backgroundMode: SceneEnvironment.Color
            clearColor: "#000000"
            antialiasingMode: SceneEnvironment.MSAA
            antialiasingQuality: SceneEnvironment.High
        }

    }

}

import QtQuick
import QtQuick.Controls
import QtQuick.Dialogs as Dialogs
import QtQuick.Layouts
import Rina.Core 1.0

Window {
    id: root

    property var project: TimelineBridge?.project ?? null
    readonly property double pFps: project?.fps ?? 60

    property string defaultCodec:      SettingsManager?.value("exportDefaultCodec",      "h264_vaapi") ?? "h264_vaapi"
    property int    defaultBitrateMbps: SettingsManager?.value("exportDefaultBitrateMbps", 15)          ?? 15
    property int    defaultCrf:         SettingsManager?.value("exportDefaultCrf",         20)          ?? 20
    property string defaultAudioCodec: SettingsManager?.value("exportDefaultAudioCodec",  "aac")       ?? "aac"
    property int    defaultAudioKbps:  SettingsManager?.value("exportDefaultAudioBitrateKbps", 192)    ?? 192

    function show() { visible = true }
    function open() { visible = true }

    title:    "メディアの書き出し"
    width:    620
    height:   580
    modality: Qt.ApplicationModal
    flags:    Qt.Dialog | Qt.WindowCloseButtonHint

    // ── 進捗オーバーレイ ───────────────────────────────────
    Rectangle {
        id: progressOverlay
        anchors.fill: parent
        color: Qt.rgba(0, 0, 0, 0.75)
        visible: TimelineBridge && TimelineBridge.isExporting
        z: 100

        ColumnLayout {
            anchors.centerIn: parent
            spacing: 16
            width: parent.width * 0.7

            Label {
                Layout.alignment: Qt.AlignHCenter
                text: "書き出し中..."
                font.pixelSize: 16
                font.bold: true
                color: "white"
            }

            ProgressBar {
                id: exportProgressBar
                Layout.fillWidth: true
                from: 0; to: 100; value: 0
            }

            Label {
                id: progressLabel
                Layout.alignment: Qt.AlignHCenter
                text: "0 / 0 フレーム"
                color: palette.mid
                font.pixelSize: 11
            }

            Button {
                Layout.alignment: Qt.AlignHCenter
                text: "キャンセル"
                onClicked: TimelineBridge.cancelExport()
            }
        }
    }

    // ── 進捗シグナルの受信 ────────────────────────────────
    Connections {
        target: TimelineBridge
        function onExportProgressChanged(progress, current, total) {
            exportProgressBar.value = progress
            progressLabel.text = current + " / " + total + " フレーム"
        }
        function onExportFinished(success, message) {
            resultPopup.message = message
            resultPopup.success = success
            resultPopup.open()
        }
    }

    // ── 完了ポップアップ ──────────────────────────────────
    Dialog {
        id: resultPopup
        property string message: ""
        property bool   success: true
        title:   success ? "完了" : "エラー"
        modal:   true
        anchors.centerIn: parent
        standardButtons: Dialog.Ok
        Label { text: resultPopup.message }
    }

    // ── メインUI ─────────────────────────────────────────
    ColumnLayout {
        anchors.fill: parent
        anchors.margins: 16
        spacing: 12

        // ファイルパス
        RowLayout {
            Layout.fillWidth: true
            TextField {
                id: filePathField
                Layout.fillWidth: true
                placeholderText: "保存先ファイルパス..."
            }
            Button {
                text: "参照..."
                onClicked: fileDialog.open()
            }
        }

        // ビデオ設定
        GroupBox {
            title: "映像"
            Layout.fillWidth: true

            GridLayout {
                columns: 4
                rowSpacing: 8
                columnSpacing: 12
                width: parent.width

                Label { text: "解像度:" }
                Label {
                    text: (project?.width ?? 1920) + " × " + (project?.height ?? 1080)
                    font.bold: true
                    Layout.columnSpan: 3
                }

                Label { text: "FPS:" }
                Label {
                    text: pFps.toFixed(3)
                    font.bold: true
                    Layout.columnSpan: 3
                }

                Label { text: "コーデック:" }
                ComboBox {
                    id: codecCombo
                    Layout.columnSpan: 3
                    Layout.fillWidth: true
                    model: [
                        { text: "H.264 – libx264 (SW)",     value: "libx264"    },
                        { text: "H.264 – NVENC (NVIDIA)",   value: "h264_nvenc" },
                        { text: "H.264 – AMF (AMD)",        value: "h264_amf"   },
                        { text: "H.264 – QSV (Intel)",      value: "h264_qsv"   },
                        { text: "H.264 – VAAPI (Linux)",    value: "h264_vaapi" },
                        { text: "HEVC – libx265 (SW)",      value: "libx265"    },
                        { text: "HEVC – NVENC (NVIDIA)",    value: "hevc_nvenc" },
                        { text: "HEVC – AMF (AMD)",         value: "hevc_amf"   },
                        { text: "HEVC – QSV (Intel)",       value: "hevc_qsv"   },
                        { text: "HEVC – VAAPI (Linux)",     value: "hevc_vaapi" },
                        { text: "AV1 – libaom (SW)",        value: "libaom-av1" },
                        { text: "AV1 – NVENC (NVIDIA)",     value: "av1_nvenc"  },
                        { text: "AV1 – AMF (AMD)",          value: "av1_amf"    },
                        { text: "AV1 – VAAPI (Linux)",      value: "av1_vaapi"  }
                    ]
                    textRole: "text"
                    Component.onCompleted: {
                        var idx = -1
                        for(var i=0; i<model.length; i++) {
                            if(model[i].value === root.defaultCodec) {
                                idx = i; break;
                            }
                        }
                        if(idx >= 0) currentIndex = idx
                        else currentIndex = 4
                    }
                }

                Label { text: "品質モード:" }
                ButtonGroup { id: qualityModeGroup }
                RadioButton {
                    id: crfRadio
                    text: "CRF"
                    ButtonGroup.group: qualityModeGroup
                    checked: true
                }
                RadioButton {
                    text: "ビットレート"
                    ButtonGroup.group: qualityModeGroup
                }

                Item { Layout.columnSpan: 1 }

                // CRF スライダー
                Label {
                    text: "CRF:"
                    visible: crfRadio.checked
                }
                RowLayout {
                    visible: crfRadio.checked
                    Layout.columnSpan: 3
                    Layout.fillWidth: true
                    Slider {
                        id: crfSlider
                        Layout.fillWidth: true
                        from: 0; to: 51; value: root.defaultCrf; stepSize: 1
                    }
                    Label {
                        text: crfSlider.value.toFixed(0)
                        Layout.preferredWidth: 28
                    }
                    Label {
                        text: crfSlider.value <= 17 ? "高品質" : crfSlider.value <= 28 ? "標準" : "低品質"
                        font.pixelSize: 10
                        color: crfSlider.value <= 17 ? "#44cc88"
                             : crfSlider.value <= 28 ? palette.text : "#cc4444"
                    }
                }

                // ビットレート入力
                Label {
                    text: "ビットレート:"
                    visible: !crfRadio.checked
                }
                RowLayout {
                    visible: !crfRadio.checked
                    Layout.columnSpan: 3
                    SpinBox {
                        id: bitrateSpin
                        from: 1; to: 500; value: root.defaultBitrateMbps; stepSize: 1
                        editable: true
                        textFromValue: v => v + " Mbps"
                        valueFromText: t => parseInt(t)
                    }
                }
            }
        }

        // オーディオ設定
        GroupBox {
            title: "音声"
            Layout.fillWidth: true

            GridLayout {
                columns: 4
                rowSpacing: 8
                columnSpacing: 12
                width: parent.width

                Label { text: "コーデック:" }
                ComboBox {
                    id: audioCodecCombo
                    Layout.columnSpan: 3
                    Layout.fillWidth: true
                    model: [
                        { text: "AAC",        value: "aac"      },
                        { text: "Opus",       value: "libopus"  },
                        { text: "MP3",        value: "libmp3lame"},
                        { text: "FLAC (可逆)", value: "flac"    },
                        { text: "PCM 16-bit", value: "pcm_s16le"}
                    ]
                    textRole: "text"
                    Component.onCompleted: {
                        var idx = -1
                        for(var i=0; i<model.length; i++) {
                            if(model[i].value === root.defaultAudioCodec) {
                                idx = i; break;
                            }
                        }
                        if(idx >= 0) currentIndex = idx
                        else currentIndex = 0
                    }
                }

                Label { text: "ビットレート:" }
                ComboBox {
                    id: audioBitrateCombo
                    Layout.columnSpan: 3
                    enabled: audioCodecCombo.currentIndex < 3  // PCM/FLACは無効
                    model: ["96 kbps", "128 kbps", "192 kbps", "256 kbps", "320 kbps"] 
                    Component.onCompleted: {
                        var bitrateList = [96, 128, 192, 256, 320]
                        var idx = bitrateList.indexOf(root.defaultAudioKbps)
                        if (idx >= 0) currentIndex = idx
                        else currentIndex = 2
                    }
                    property int bitrate: [96000, 128000, 192000, 256000, 320000][currentIndex]
                }
            }
        }

        // 範囲設定
        GroupBox {
            title: "範囲"
            Layout.fillWidth: true

            RowLayout {
                width: parent.width
                spacing: 12

                CheckBox {
                    id: fullRangeCheck
                    text: "タイムライン全体"
                    checked: true
                }

                Label { text: "開始:" }
                SpinBox {
                    id: startFrameSpin
                    enabled: !fullRangeCheck.checked
                    from: 0
                    to: endFrameSpin.value - 1
                    value: 0
                    editable: true
                }

                Label { text: "終了:" }
                SpinBox {
                    id: endFrameSpin
                    enabled: !fullRangeCheck.checked
                    from: startFrameSpin.value + 1
                    to: 99999
                    value: 300
                    editable: true
                    Component.onCompleted: {
                        if (TimelineBridge && TimelineBridge.timelineDuration > 0)
                            value = TimelineBridge.timelineDuration
                    }
                    Connections {
                        target: TimelineBridge
                        function onClipsChanged() {
                            if (TimelineBridge && TimelineBridge.timelineDuration > 0)
                                endFrameSpin.value = TimelineBridge.timelineDuration
                        }
                    }
                }

                Label {
                    text: {
                        var s = fullRangeCheck.checked ? 0 : startFrameSpin.value
                        var e = fullRangeCheck.checked
                            ? (TimelineBridge ? TimelineBridge.timelineDuration : 300)
                            : endFrameSpin.value
                        var sec = (e - s) / pFps
                        return "(" + (e - s) + " フレーム / " + sec.toFixed(2) + " 秒)"
                    }
                    font.pixelSize: 11
                    color: palette.mid
                }
            }
        }

        Item { Layout.fillHeight: true }

        // ボタン
        RowLayout {
            Layout.fillWidth: true
            Item { Layout.fillWidth: true }
            Button {
                text: "キャンセル"
                onClicked: root.close()
            }
            Button {
                text: "書き出し開始"
                enabled: filePathField.text !== ""
                highlighted: true
                onClicked: {
                    var codec = codecCombo.model[codecCombo.currentIndex].value
                    var audioCodec = audioCodecCombo.model[audioCodecCombo.currentIndex].value
                    TimelineBridge.exportVideoAsync({
                        "width":          project?.width  ?? 1920,
                        "height":         project?.height ?? 1080,
                        "fps_num":        Math.round(pFps * 1000),
                        "fps_den":        1000,
                        "bitrate":        bitrateSpin.value * 1_000_000,
                        "crf":            crfRadio.checked ? crfSlider.value : -1,
                        "codecName":      codec,
                        "audioCodecName": audioCodec,
                        "audioBitrate":   audioBitrateCombo.bitrate,
                        "outputUrl":      filePathField.text,
                        "startFrame":     fullRangeCheck.checked ? 0 : startFrameSpin.value,
                        "endFrame":       fullRangeCheck.checked ? -1 : endFrameSpin.value
                    })
                }
            }
        }
    }

    Dialogs.FileDialog {
        id: fileDialog
        title: "保存先を指定"
        fileMode: Dialogs.FileDialog.SaveFile
        nameFilters: ["MP4 Video (*.mp4)", "MKV Video (*.mkv)", "All files (*)"]
        onAccepted: {
            var path = selectedFile.toString()
            filePathField.text = Qt.platform.os === "windows"
                ? path.replace(/^file:\/{3}/, "")
                : path.replace(/^file:\/\//, "")
        }
    }
}

import Qt.labs.platform as Platform
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts
import QtQuick.Window
import "common" as Common

ApplicationWindow {
    id: mainWin

    visible: true
    width: 640
    height: 360
    x: 100
    y: 100
    title: "Rina - プレビュー"
    // お前はこれで死ねぇ！！！！！
    onClosing: (close) => {
        if (WindowManager)
            WindowManager.requestQuit();

        close.accepted = true;
    }
    // 起動時に自分自身(Window)をコントローラーに渡す
    Component.onCompleted: {
        if (TimelineBridge)
            TimelineBridge.setCompositeView(compositeView);

    }

    FontLoader {
        source: "qrc:/resources/remixicon.ttf"
    }

    // アクション定義 (ショートカット用)
    Action {
        id: newAction

        text: "新規プロジェクト"
        shortcut: "Ctrl+N"
        onTriggered: console.log("New Project")
    }

    Action {
        id: saveProjectAction // プロジェクトの上書き保存用アクション

        text: "プロジェクトの上書き保存"
        shortcut: "Ctrl+S"
        onTriggered: {
            if (TimelineBridge)
                TimelineBridge.saveProject("");

        }
    }

    Action {
        id: loadAction

        text: "プロジェクトを開く"
        shortcut: "Ctrl+O"
        onTriggered: loadDialog.open()
    }

    Action {
        id: saveAsProjectAction // プロジェクトを名前を付けて保存用アクション

        text: "プロジェクトを名前を付けて保存..."
        shortcut: "Ctrl+Shift+S"
        onTriggered: saveDialog.open()
    }

    Action {
        id: quitAction

        text: "終了"
        shortcut: "Ctrl+Q"
        onTriggered: {
            if (WindowManager)
                WindowManager.requestQuit();

        }
    }

    Action {
        id: undoAction

        text: "元に戻す"
        shortcut: "Ctrl+Z"
        onTriggered: {
            if (TimelineBridge)
                TimelineBridge.undo();

        }
    }

    Action {
        id: redoAction

        text: "やり直す"
        shortcut: "Ctrl+Shift+Z"
        onTriggered: {
            if (TimelineBridge)
                TimelineBridge.redo();

        }
    }

    Platform.MessageDialog {
        id: errorDialog

        title: "エラー"
        buttons: Platform.MessageDialog.Ok
    }

    Platform.MessageDialog {
        id: aboutDialog

        title: "Rinaについて"
        text: "Rina (Rolling Release)\n\nRina is not AviUtl.\n\nこのソフトウェアはGNU Affero General Public License Version 3に基づいて公開されています。\n\nhttps://codeberg.org/taisho-guy/Rina"
        buttons: Platform.MessageDialog.Ok
    }

    Connections {
        function onErrorOccurred(message) {
            errorDialog.text = message;
            errorDialog.open();
        }

        target: TimelineBridge
    }

    // FPSと再生速度の同期設定
    Binding {
        target: TimelineBridge ? TimelineBridge.transport : null
        property: "fps"
        value: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.fps : 60
    }

    Connections {
        function onPlaybackSpeedChanged() {
            if (TimelineBridge)
                TimelineBridge.syncPlaybackSpeed();

        }

        target: TimelineBridge ? TimelineBridge.transport : null
    }

    Connections {
        function onSampleRateChanged() {
            if (TimelineBridge)
                TimelineBridge.updateAudioSampleRate();

        }

        target: TimelineBridge ? TimelineBridge.project : null
    }

    Platform.FileDialog {
        id: saveDialog

        fileMode: Platform.FileDialog.SaveFile
        nameFilters: ["Rina Project files (*.rina)", "JSON files (*.json)"]
        defaultSuffix: "rina"
        onAccepted: {
            if (TimelineBridge)
                TimelineBridge.saveProject(file);

        }
    }

    Platform.FileDialog {
        id: loadDialog

        fileMode: Platform.FileDialog.OpenFile
        nameFilters: ["Rina Project files (*.rina)", "JSON files (*.json)"]
        onAccepted: {
            if (TimelineBridge)
                TimelineBridge.loadProject(file);

        }
    }

    ExportDialog {
        id: exportDialog
    }

    ColumnLayout {
        anchors.fill: parent
        spacing: 0

        CompositeView {
            id: compositeView

            Layout.fillWidth: true
            Layout.fillHeight: true
            // タイムラインウィンドウからレイヤー状態を取得
            getLayerVisible: function(layer) {
                var tlWin = WindowManager.getWindow("timeline");
                if (tlWin && tlWin.getLayerVisible)
                    return tlWin.getLayerVisible(layer);

                return true;
            }
        }

        // 再生コントロールバー
        Rectangle {
            Layout.fillWidth: true
            Layout.preferredHeight: 38
            color: mainWin.palette.window

            RowLayout {
                anchors.fill: parent
                anchors.leftMargin: 10
                anchors.rightMargin: 10
                spacing: 10

                // シークバー
                Slider {
                    id: seekSlider

                    Layout.fillWidth: true
                    from: 0
                    to: {
                        // クリップの末尾を取得して動的に拡張
                        var maxEnd = 0;
                        var clipList = (TimelineBridge && TimelineBridge.clips) ? TimelineBridge.clips : [];
                        for (var j = 0; j < clipList.length; j++) {
                            var clip = clipList[j];
                            var end = clip.startFrame + clip.durationFrames;
                            if (end > maxEnd)
                                maxEnd = end;

                        }
                        return Math.max(1, maxEnd + 1);
                    }
                    value: (TimelineBridge && TimelineBridge.transport) ? TimelineBridge.transport.currentFrame : 0
                    onMoved: {
                        if (TimelineBridge && TimelineBridge.transport)
                            TimelineBridge.transport.setCurrentFrame_seek(value);

                    }
                }

                Label {
                    text: Math.floor(seekSlider.value) + " / " + Math.floor(seekSlider.to)
                    font.pixelSize: 12
                    color: mainWin.palette.text
                }

                // 操作ボタン
                RowLayout {
                    spacing: 0

                    Button {
                        Layout.preferredWidth: 32
                        Layout.preferredHeight: 32
                        flat: true
                        onClicked: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.setCurrentFrame_seek(Math.max(0, TimelineBridge.transport.currentFrame - 1));

                        }

                        contentItem: Common.RinaIcon {
                            iconName: "arrow_left_s_line"
                            size: 24
                            color: parent.hovered ? parent.palette.highlight : parent.palette.text
                        }

                    }

                    Button {
                        Layout.preferredWidth: 32
                        Layout.preferredHeight: 32
                        flat: true
                        onClicked: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.togglePlay();

                        }

                        contentItem: Common.RinaIcon {
                            iconName: (TimelineBridge && TimelineBridge.transport && TimelineBridge.transport.isPlaying) ? "pause_fill" : "play_fill"
                            size: 24
                            color: parent.hovered ? parent.palette.highlight : parent.palette.text
                        }

                    }

                    Button {
                        Layout.preferredWidth: 32
                        Layout.preferredHeight: 32
                        flat: true
                        onClicked: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.setCurrentFrame_seek(TimelineBridge.transport.currentFrame + 1);

                        }

                        contentItem: Common.RinaIcon {
                            iconName: "arrow_right_s_line"
                            size: 24
                            color: parent.hovered ? parent.palette.highlight : parent.palette.text
                        }

                    }

                }

                // 再生速度
                RowLayout {
                    spacing: 5

                    Label {
                        text: "速度"
                        color: mainWin.palette.text
                        font.pixelSize: 12
                    }

                    SpinBox {
                        from: SettingsManager ? SettingsManager.value("timelineZoomMin", 10) : 10
                        to: SettingsManager ? SettingsManager.value("timelineZoomMax", 400) : 400
                        stepSize: SettingsManager ? SettingsManager.value("timelineZoomStep", 10) : 10
                        editable: true
                        Layout.preferredWidth: 80
                        Layout.preferredHeight: 28
                        // 値のバインディング
                        value: (TimelineBridge && TimelineBridge.transport) ? Math.round(TimelineBridge.transport.playbackSpeed * 100) : 100
                        onValueModified: {
                            if (TimelineBridge && TimelineBridge.transport)
                                TimelineBridge.transport.playbackSpeed = value / 100;

                        }
                        textFromValue: function(value, locale) {
                            return (value / 100).toFixed(1) + "x";
                        }
                        valueFromText: function(text, locale) {
                            return Number.fromLocaleString(locale, text.replace("x", "")) * 100;
                        }
                    }

                }

            }

        }

    }

    // View3D の背後に黒背景を強制しない
    background: Rectangle {
        color: mainWin.palette.window
    }

    menuBar: MenuBar {
        Menu {
            title: "ファイル"

            Common.IconMenuItem {
                action: newAction
                iconName: "file_add_line"
            }

            Common.IconMenuItem {
                action: loadAction
                iconName: "folder_open_line"
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                action: saveProjectAction
                iconName: "save_line"
            }

            Common.IconMenuItem {
                action: saveAsProjectAction
                iconName: "save_3_line"
            }

            MenuSeparator {
            }

            Common.IconMenuItem {
                text: "メディアの書き出し..."
                iconName: "movie_line"
                enabled: TimelineBridge && TimelineBridge.project
