import QtQuick
import QtQuick.Controls
import QtQuick.Layouts
import "common" as Common
import "timeline" // サブフォルダのモジュールをインポート

Common.RinaWindow {
    id: timelineWindow

    // 定数・設定
    property var settings: SettingsManager.settings
    readonly property int layerCount: settings.timelineMaxLayers || 128
    readonly property int layerHeight: settings.timelineTrackHeight || 30
    readonly property int rulerHeight: settings.timelineRulerHeight || 32
    readonly property int headerWidth: settings.timelineLayerHeaderWidth || 60
    readonly property int clipResizeHandleWidth: settings.timelineClipResizeHandleWidth || 10
    readonly property int sceneTabHeight: settings.timelineHeaderHeight || 28
    // レイヤー状態のグローバル管理（LayerHeaderからの通知を受け取る）
    property var globalLayerStates: ({
    })

    function getLayerVisible(layer) {
        var state = globalLayerStates[layer];
        return state ? state.visible : true;
    }

    title: "Timeline"
    width: 1280
    height: 300

    // グリッド設定ウィンドウ
    Loader {
        id: gridSettingsLoader

        active: false
        source: "timeline/GridSettingsWindow.qml"
        onLoaded: item.open(timelineView)
    }

    ColumnLayout {
        anchors.fill: parent
        spacing: 0

        // 1. シーンタブ
        RowLayout {
            Layout.fillWidth: true
            Layout.preferredHeight: sceneTabHeight
            spacing: 0
            z: 1

            ScrollView {
                Layout.fillWidth: true
                Layout.fillHeight: true
                ScrollBar.horizontal.policy: ScrollBar.AlwaysOff
                ScrollBar.vertical.policy: ScrollBar.AlwaysOff

                TabBar {
                    id: sceneTabBar

                    // ScrollView内で適切に広がるように設定
                    width: Math.max(parent.width, contentWidth)

                    Repeater {
                        id: sceneRepeater

                        model: TimelineBridge ? TimelineBridge.scenes : []

                        TabButton {
                            id: tabBtn

                            checked: TimelineBridge && TimelineBridge.currentSceneId === modelData.id
                            onClicked: {
                                if (TimelineBridge)
                                    TimelineBridge.switchScene(modelData.id);

                            }

                            MouseArea {
                                anchors.fill: parent
                                acceptedButtons: Qt.RightButton
                                onClicked: {
                                    var win = WindowManager.getWindow("sceneSettings");
                                    if (win)
                                        win.openForScene(modelData.id, modelData.name, modelData.width !== undefined ? modelData.width : 1920, modelData.height !== undefined ? modelData.height : 1080, modelData.fps !== undefined ? modelData.fps : 60, modelData.totalFrames !== undefined ? modelData.totalFrames : 300);

                                }
                            }

                            contentItem: RowLayout {
                                spacing: 4

                                Text {
                                    text: modelData.name
                                    font: tabBtn.font
                                    color: palette.text
                                    horizontalAlignment: Text.AlignHCenter
                                    verticalAlignment: Text.AlignVCenter
                                    elide: Text.ElideRight
                                    Layout.maximumWidth: 200
                                }

                                Button {
                                    flat: true
                                    visible: modelData.id !== 0
                                    Layout.preferredWidth: 20
                                    Layout.preferredHeight: 20
                                    onClicked: {
                                        if (TimelineBridge)
                                            TimelineBridge.removeScene(modelData.id);

                                    }

                                    contentItem: Common.RinaIcon {
                                        iconName: "close_line"
                                        size: 14
                                        color: parent.hovered ? parent.palette.highlight : parent.palette.text
                                    }

                                }

                            }

                        }

                    }

                }

            }

            // シーン追加ボタン
            Button {
                flat: true
                Layout.preferredWidth: 40
                Layout.fillHeight: true
                onClicked: TimelineBridge.createScene("Scene " + (sceneRepeater.count + 1))

                contentItem: Common.RinaIcon {
                    iconName: "add_line"
                    size: 20
                    color: parent.hovered ? parent.palette.highlight : parent.palette.text
                }

            }

        }

        // 2. 定規
        Ruler {
            targetFlickable: timelineView.flickable
            rulerHeight: timelineWindow.rulerHeight
            timeWidth: timelineWindow.headerWidth
            fps: TimelineBridge && TimelineBridge.project ? TimelineBridge.project.fps : 60
        }

        // 3. メインエリア
        RowLayout {
            Layout.fillWidth: true
            Layout.fillHeight: true
            spacing: 0

            LayerHeader {
                id: layerHeader

                headerWidth: timelineWindow.headerWidth
                layerHeight: timelineWindow.layerHeight
                layerCount: timelineWindow.layerCount
                syncFlickable: timelineView.flickable
                onLayerVisibilityChanged: (layer, visible) => {
                    if (!globalLayerStates[layer])
                        globalLayerStates[layer] = {
                        "visible": true,
                        "locked": false
                    };

                    globalLayerStates[layer].visible = visible;
                    globalLayerStates = globalLayerStates; // 強制再評価
                }
                onLayerLockChanged: (layer, locked) => {
                    if (!globalLayerStates[layer])
                        globalLayerStates[layer] = {
                        "visible": true,
                        "locked": false
                    };

                    globalLayerStates[layer].locked = locked;
                    globalLayerStates = globalLayerStates;
                }
            }

            TimelineView {
                id: timelineView

                Layout.fillWidth: true
                Layout.fillHeight: true
                layerHeight: timelineWindow.layerHeight
                layerCount: timelineWindow.layerCount
                clipResizeHandleWidth: timelineWindow.clipResizeHandleWidth
                getLayerLocked: (layer) => {
                    return layerHeader.getLayerLocked(layer);
                }
                onGridSettingsRequested: {
                    if (!gridSettingsLoader.active)
                        gridSettingsLoader.active = true;
                    else
                        gridSettingsLoader.item.open(timelineView);
                }
            }

        }

    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Common.RinaWindow {
    id: root

    // 設定対象のTimelineView
    property var targetView: null

    function open(view) {
        targetView = view;
        if (view && view.gridSettings) {
            var s = view.gridSettings;
            if (s.mode === "BPM")
                modeCombo.currentIndex = 1;
            else if (s.mode === "Frame")
                modeCombo.currentIndex = 2;
            else
                modeCombo.currentIndex = 0; // Auto
            bpmField.text = s.bpm || 120;
            offsetField.text = s.offset || 0;
            intervalField.text = s.interval || 10;
            subdivisionField.text = s.subdivision || 4;
        }
        root.show();
        root.raise();
    }

    function apply() {
        if (!targetView)
            return ;

        var modeKey = "Auto";
        if (modeCombo.currentIndex === 1)
            modeKey = "BPM";

        if (modeCombo.currentIndex === 2)
            modeKey = "Frame";

        // 新しい設定オブジェクトを代入することで、TimelineView側のonGridSettingsChangedを発火させる
        targetView.gridSettings = {
            "mode": modeKey,
            "bpm": parseFloat(bpmField.text) || 120,
            "offset": parseFloat(offsetField.text) || 0,
            "interval": parseInt(intervalField.text) || 10,
            "subdivision": parseInt(subdivisionField.text) || 4
        };
    }

    title: "グリッド設定"
    width: 320
    height: 300

    ColumnLayout {
        anchors.fill: parent
        anchors.margins: 15
        spacing: 10

        RowLayout {
            Label {
                text: "モード:"
            }

            ComboBox {
                id: modeCombo

                Layout.fillWidth: true
                model: ["自動 (秒/フレーム)", "BPM (音楽)", "フレーム数固定"]
                onCurrentIndexChanged: apply()
            }

        }

        // BPM設定
        GroupBox {
            title: "BPM設定"
            visible: modeCombo.currentIndex === 1
            Layout.fillWidth: true

            GridLayout {
                columns: 2

                Label {
                    text: "BPM:"
                }

                TextField {
                    id: bpmField

                    text: "120"
                    selectByMouse: true
                    onEditingFinished: apply()
                }

                Label {
                    text: "拍子 (分割数):"
                }

                TextField {
                    id: subdivisionField

                    text: "4"
                    selectByMouse: true
                    onEditingFinished: apply()
                }

                Label {
                    text: "オフセット (秒):"
                }

                TextField {
                    id: offsetField

                    text: "0.0"
                    selectByMouse: true
                    onEditingFinished: apply()
                }

            }

        }

        // フレーム設定
        GroupBox {
            title: "フレーム設定"
            visible: modeCombo.currentIndex === 2
            Layout.fillWidth: true

            GridLayout {
                columns: 2

                Label {
                    text: "間隔 (Frames):"
                }

                TextField {
                    id: intervalField

                    text: "10"
                    selectByMouse: true
                    onEditingFinished: apply()
                }

            }

        }

        // Spacer
        Item {
            Layout.fillHeight: true
        }

        Button {
            text: "閉じる"
            Layout.alignment: Qt.AlignRight
            onClicked: root.close()
        }

    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Rectangle {
    id: headerRoot

    property int headerWidth: 60
    property int layerHeight: 30
    property int layerCount: 128
    property var syncFlickable: null // TimelineViewのFlickable
    // レイヤー状態管理 (内部保持)
    property var _layerStates: ({
    })

    // 外部への通知シグナル
    signal layerVisibilityChanged(int layer, bool visible)
    signal layerLockChanged(int layer, bool locked)

    function clamp(v, lo, hi) {
        return Math.max(lo, Math.min(hi, v));
    }

    function getLayerVisible(layer) {
        var state = _layerStates[layer];
        return state ? state.visible : true;
    }

    function getLayerLocked(layer) {
        var state = _layerStates[layer];
        return state ? state.locked : false;
    }

    function setLayerVisible(layer, visible) {
        if (!_layerStates[layer])
            _layerStates[layer] = {
            "visible": true,
            "locked": false
        };

        _layerStates[layer].visible = visible;
        layerVisibilityChanged(layer, visible);
        // 強制的に再評価を促す
        _layerStatesChanged();
    }

    function setLayerLocked(layer, locked) {
        if (!_layerStates[layer])
            _layerStates[layer] = {
            "visible": true,
            "locked": false
        };

        _layerStates[layer].locked = locked;
        layerLockChanged(layer, locked);
        _layerStatesChanged();
    }

    Layout.preferredWidth: headerWidth
    Layout.fillHeight: true
    color: palette.button
    z: 2

    Flickable {
        id: layerHeaderFlickable

        anchors.fill: parent
        contentHeight: layerCount * layerHeight
        // TimelineViewと同期
        contentY: syncFlickable ? syncFlickable.contentY : 0
        interactive: false // 独自のホイール処理を行うため
        clip: true

        Column {
            Repeater {
                model: layerCount

                // レイヤーボタン (AviUtl風)
                Button {
                    id: layerBtn

                    property int layerIndex: index
                    property bool isVisible: headerRoot.getLayerVisible(layerIndex)
                    property bool isLocked: headerRoot.getLayerLocked(layerIndex)

                    width: headerRoot.headerWidth
                    height: headerRoot.layerHeight
                    flat: true
                    // 左クリック: 表示/非表示トグル
                    onClicked: {
                        headerRoot.setLayerVisible(layerIndex, !isVisible);
                    }

                    // 右クリック: コンテキストメニュー
                    MouseArea {
                        anchors.fill: parent
                        acceptedButtons: Qt.RightButton
                        onClicked: {
                            layerMenu.layerIndex = layerBtn.layerIndex;
                            layerMenu.popup();
                        }
                    }

                    // 背景色: 非表示時は暗く、ロック時は赤みがかる
                    background: Rectangle {
                        color: {
                            if (!layerBtn.isVisible)
                                return Qt.darker(palette.button, 1.5);

                            if (layerBtn.isLocked)
                                return Qt.rgba(0.6, 0.3, 0.3, 1);

                            return (layerBtn.layerIndex % 2 == 0) ? palette.button : Qt.darker(palette.button, 1.1);
                        }
                        border.color: palette.mid
                        border.width: 1
                    }

                    // レイヤー番号表示
                    contentItem: Item {
                        Text {
                            anchors.centerIn: parent
                            text: (layerBtn.layerIndex + 1).toString()
                            color: {
                                if (!layerBtn.isVisible)
                                    return palette.mid;

                                if (layerBtn.isLocked)
                                    return "#ffcccc";

                                return palette.text;
                            }
                            font.pixelSize: 12
                            font.bold: layerBtn.isVisible && !layerBtn.isLocked
                        }

                        // 状態インジケーター (右上に小さな記号)
                        Row {
                            anchors.right: parent.right
                            anchors.top: parent.top
                            anchors.margins: 2
                            spacing: 2

                            Common.RinaIcon {
                                visible: layerBtn.isLocked
                                iconName: "lock_fill"
                                size: 10
                                color: "#ffcccc"
                            }

                            Common.RinaIcon {
                                visible: !layerBtn.isVisible
                                iconName: "eye_off_line"
                                size: 10
                                color: palette.mid
                            }

                        }

                    }

                }

            }

        }

    }

    // レイヤーコンテキストメニュー
    Menu {
        id: layerMenu

        property int layerIndex: 0

        Common.IconMenuItem {
            text: "表示/非表示を切り替え"
            iconName: headerRoot.getLayerVisible(layerMenu.layerIndex) ? "eye_off_line" : "eye_line"
            onTriggered: {
                var visible = headerRoot.getLayerVisible(layerMenu.layerIndex);
                headerRoot.setLayerVisible(layerMenu.layerIndex, !visible);
            }
        }

        MenuSeparator {
        }

        Common.IconMenuItem {
            text: {
                var locked = headerRoot.getLayerLocked(layerMenu.layerIndex);
                return locked ? "ロックを解除" : "ロック";
            }
            iconName: headerRoot.getLayerLocked(layerMenu.layerIndex) ? "lock_unlock_line" : "lock_line"
            onTriggered: {
                var locked = headerRoot.getLayerLocked(layerMenu.layerIndex);
                headerRoot.setLayerLocked(layerMenu.layerIndex, !locked);
            }
        }

        MenuSeparator {
        }

        Common.IconMenuItem {
            text: "すべて表示"
            iconName: "eye_line"
            onTriggered: {
                for (var i = 0; i < headerRoot.layerCount; i++) {
                    headerRoot.setLayerVisible(i, true);
                }
            }
        }

        Common.IconMenuItem {
            text: "すべて非表示"
            iconName: "eye_off_line"
            onTriggered: {
                for (var i = 0; i < headerRoot.layerCount; i++) {
                    headerRoot.setLayerVisible(i, false);
                }
            }
        }

    }

    // 縦スクロール専用マウスエリア
    MouseArea {
        anchors.fill: parent
        acceptedButtons: Qt.NoButton
        z: -1
        hoverEnabled: true
        onWheel: (wheel) => {
            if (!syncFlickable)
                return ;

            var dy = wheel.angleDelta.y;
            if (wheel.pixelDelta && wheel.pixelDelta.y !== 0)
                dy = wheel.pixelDelta.y * 10;

            var nextY = syncFlickable.contentY - dy;
            var maxY = Math.max(0, syncFlickable.contentHeight - syncFlickable.height);
            syncFlickable.contentY = clamp(nextY, 0, maxY);
            wheel.accepted = true;
        }
    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

Rectangle {
    id: rulerRoot

    // 外部から注入される依存プロパティ
    property var targetFlickable: null
    property int rulerHeight: 32
    property int timeWidth: 60
    property double fps: 60
    property alias canvas: rulerCanvas

    // ユーティリティ
    function pxToFrame(px, contentX) {
        var scale = TimelineBridge ? TimelineBridge.timelineScale : 1;
        var x = px + contentX;
        return Math.max(0, Math.round((x - timeWidth) / scale));
    }

    function clamp(v, lo, hi) {
        return Math.max(lo, Math.min(hi, v));
    }

    function zoomAt(wheel, zoomFactor) {
        if (!TimelineBridge || !targetFlickable)
            return ;

        var oldScale = TimelineBridge.timelineScale;
        var newScale = clamp(oldScale * zoomFactor, 0.1, 20);
        if (Math.abs(newScale - oldScale) < 1e-06)
            return ;

        var mouseX = wheel.x !== undefined ? wheel.x : (wheel.position ? wheel.position.x : 0);
        var anchorFrame = (targetFlickable.contentX + mouseX - timeWidth) / oldScale; // timeWidth補正
        TimelineBridge.timelineScale = newScale;
        // ズーム後の位置補正
        var newContentX = anchorFrame * newScale - mouseX + timeWidth;
        var maxX = Math.max(0, targetFlickable.contentWidth - targetFlickable.width);
        targetFlickable.contentX = clamp(newContentX, 0, maxX);
    }

    Layout.fillWidth: true
    Layout.preferredHeight: rulerHeight
    color: palette.window
    z: 10

    // Canvas再描画トリガー
    Connections {
        function onContentXChanged() {
            rulerCanvas.requestPaint();
        }

        target: targetFlickable
    }

    RowLayout {
        anchors.fill: parent
        spacing: 0

        // 左上の空白（レイヤーヘッダーの上）
        Rectangle {
            Layout.preferredWidth: timeWidth
            Layout.fillHeight: true
            color: palette.base
            border.color: palette.mid
            border.width: 1
            z: 100

            Text {
                anchors.centerIn: parent
                text: TimelineBridge && TimelineBridge.transport ? TimelineBridge.transport.currentFrame + "f" : "0f"
                font.pixelSize: 11
                font.bold: true
                color: palette.highlight
            }

        }

        // 定規本体
        Item {
            Layout.fillWidth: true
            Layout.fillHeight: true
            clip: true

            Canvas {
                id: rulerCanvas

                property double scale: TimelineBridge ? TimelineBridge.timelineScale : 1
                property double offsetX: targetFlickable ? targetFlickable.contentX : 0
                property int fpsInt: Math.round(rulerRoot.fps)

                anchors.fill: parent
                onScaleChanged: requestPaint()
                onOffsetXChanged: requestPaint()
                onPaint: {
                    var ctx = getContext("2d");
                    ctx.clearRect(0, 0, width, height);
                    if (!TimelineBridge)
                        return ;

                    var viewWidth = width;
                    var viewOffsetX = offsetX;
                    // 簡易的なグリッド描画（詳細は元のロジックを維持）
                    var frameInterval = 60;
                    // 仮
                    if (scale > 5)
                        frameInterval = 10;
                    else if (scale > 1)
                        frameInterval = 30;
                    else if (scale > 0.5)
                        frameInterval = 60;
                    else
                        frameInterval = 300;
                    var startFrame = Math.floor(viewOffsetX / scale);
                    var endFrame = Math.ceil((viewOffsetX + viewWidth) / scale);
                    var alignedStart = Math.floor(startFrame / frameInterval) * frameInterval;
                    ctx.strokeStyle = palette.text;
                    ctx.fillStyle = palette.text;
                    ctx.lineWidth = 1;
                    ctx.font = "10px sans-serif";
                    for (var f = alignedStart; f <= endFrame; f += frameInterval) {
                        var pixelX = f * scale - viewOffsetX;
                        var isSecond = (f % fpsInt === 0);
                        // 大目盛
                        ctx.beginPath();
                        ctx.moveTo(pixelX, 15);
                        ctx.lineTo(pixelX, height);
                        ctx.stroke();
                        if (isSecond) {
                            // 時:分:秒 形式の時間表示
                            var totalSeconds = f / fpsInt;
                            var hours = Math.floor(totalSeconds / 3600);
                            var minutes = Math.floor((totalSeconds % 3600) / 60);
                            var seconds = Math.floor(totalSeconds % 60);
                            var timeLabel;
                            if (hours > 0)
                                timeLabel = hours + ":" + ("0" + minutes).slice(-2) + ":" + ("0" + seconds).slice(-2);
                            else if (minutes > 0)
                                timeLabel = minutes + ":" + ("0" + seconds).slice(-2);
                            else
                                timeLabel = seconds + "s";
                            ctx.fillStyle = palette.text;
                            ctx.fillText(timeLabel, pixelX + 3, 12);
                            // フレーム番号を小さく表示
                            ctx.font = "8px sans-serif";
                            ctx.fillStyle = palette.mid;
                            ctx.fillText(f + "f", pixelX + 3, 24);
                            ctx.font = "10px sans-serif";
                        } else {
                            // フレーム数テキスト（秒単位以外）
                            ctx.fillStyle = palette.text;
                            ctx.fillText(f, pixelX + 2, 12);
                        }
                    }
                }
            }

            // マウス操作（スクラブ & ズーム）
            MouseArea {
                anchors.fill: parent
                hoverEnabled: true
                acceptedButtons: Qt.LeftButton | Qt.RightButton
                onPressed: (mouse) => {
                    if (mouse.button === Qt.LeftButton) {
                        if (TimelineBridge && TimelineBridge.transport && targetFlickable)
                            TimelineBridge.transport.currentFrame = pxToFrame(mouse.x, targetFlickable.contentX);

                    }
                }
                onPositionChanged: (mouse) => {
                    if (pressed && mouse.buttons & Qt.LeftButton) {
                        if (TimelineBridge && TimelineBridge.transport && targetFlickable)
                            TimelineBridge.transport.currentFrame = pxToFrame(mouse.x, targetFlickable.contentX);

                    }
                }
                onWheel: (wheel) => {
                    var dy = (wheel.angleDelta.y !== 0) ? wheel.angleDelta.y : (wheel.pixelDelta.y * 10);
                    var zoomFactor = (dy > 0) ? 1.1 : 0.9;
                    zoomAt(wheel, zoomFactor);
                    wheel.accepted = true;
                }
            }

        }

    }

}

import "../common" as Common
import QtQuick
import QtQuick.Controls
import QtQuick.Layouts

ScrollView {
    id: timelineViewRoot

    property alias flickable: timelineFlickable
    property alias contentX: timelineFlickable.contentX
    property alias contentY: timelineFlickable.contentY
    property int layerHeight: 30
    property int layerCount: 128
    property int clipResizeHandleWidth: 6
    property var getLayerLocked: function(layer) {
        return false;
    }
    property int contextClickFrame: 0
    property int contextClickLayer: 0
    property bool enableSnap: SettingsManager.settings.enableSnap
    property int tailPaddingFrames: 120
    property var gridSettings: ({
        "mode": "Auto",
        "bpm": 120,
        "offset": 0,
        "interval": 10,
        "subdivision": 4
    })
    readonly property int maxClipEndFrame: {
        var maxEnd = 0;
        var clipList = (TimelineBridge && TimelineBridge.clips) ? TimelineBridge.clips : [];
        for (var i = 0; i < clipList.length; i++) {
            var end = clipList[i].startFrame + clipList[i].durationFrames;
            if (end > maxEnd)
                maxEnd = end;

        }
        return maxEnd;
    }
    readonly property int timelineLengthFrames: Math.max(100, maxClipEndFrame + tailPaddingFrames)

    signal gridSettingsRequested()

    function clamp(v, lo, hi) {
        return Math.max(lo, Math.min(hi, v));
    }

    function getGridInterval() {
        if (!TimelineBridge)
            return 1;

        var scale = TimelineBridge.timelineScale;
        var projectFps = (TimelineBridge.project && TimelineBridge.project.fps) ? TimelineBridge.project.fps : 60;
        if (gridSettings.mode === "BPM") {
            var beatFrames = projectFps / (gridSettings.bpm / 60);
            var bpmDiv = scale > 3 ? 4 : scale > 1.5 ? 2 : 1;
            return beatFrames / bpmDiv;
        }
        if (gridSettings.mode === "Frame")
            return gridSettings.interval;

        // Auto
        if (scale < 0.5)
            return Math.ceil(projectFps);

        if (scale < 1.5)
            return 10;

        if (scale < 3)
            return 5;

        return 1;
    }

    function snapFrame(frame) {
        if (!enableSnap)
            return Math.round(frame);

        var step = getGridInterval();
        var offset = (gridSettings.mode === "BPM" && TimelineBridge && TimelineBridge.project) ? gridSettings.offset * TimelineBridge.project.fps : 0;
        return Math.max(0, Math.round((Math.round((frame - offset) / step) * step) + offset));
    }

    onGridSettingsChanged: timelineGrid.requestPaint()
    clip: true
    ScrollBar.horizontal.policy: ScrollBar.AlwaysOn
    ScrollBar.vertical.policy: ScrollBar.AlwaysOn

    Flickable {
        id: timelineFlickable

        contentWidth: Math.max(width, timelineLengthFrames * (TimelineBridge ? TimelineBridge.timelineScale : 1))
        contentHeight: layerCount * layerHeight
        interactive: true

        Connections {
            function onContentXChanged() {
                timelineGrid.requestPaint();
            }

            function onContentYChanged() {
                timelineGrid.requestPaint();
            }

            target: timelineFlickable
        }

        Connections {
            function onTimelineScaleChanged() {
                timelineGrid.requestPaint();
            }

            target: TimelineBridge ?? null
        }

        Item {
            x: timelineFlickable.contentX
            y: timelineFlickable.contentY
            width: timelineFlickable.width
            height: timelineFlickable.height
            z: -1

            Canvas {
                id: timelineGrid

                anchors.fill: parent
                onPaint: {
                    var ctx = getContext("2d");
                    ctx.clearRect(0, 0, width, height);
                    ctx.lineWidth = 1;
                    // 水平区切り線
                    ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.2);
                    var startY = timelineFlickable.contentY;
                    for (var i = 0; i < layerCount; i++) {
                        var ly = i * layerHeight - startY;
                        if (ly < -layerHeight || ly > height)
                            continue;

                        ctx.beginPath();
                        ctx.moveTo(0, ly);
                        ctx.lineTo(width, ly);
                        ctx.stroke();
                    }
                    if (!TimelineBridge)
                        return ;

                    // 垂直グリッド線
                    var scale = TimelineBridge.timelineScale;
                    var contentX = timelineFlickable.contentX;
                    var step = timelineViewRoot.getGridInterval();
                    var offsetF = (gridSettings.mode === "BPM" && TimelineBridge.project) ? gridSettings.offset * TimelineBridge.project.fps : 0;
                    var isBpm = (gridSettings.mode === "BPM");
                    var bpmDiv = isBpm ? (scale > 3 ? 4 : scale > 1.5 ? 2 : 1) : 1;
                    var startN = Math.ceil((Math.floor(contentX / scale) - offsetF) / step);
                    var endN = Math.floor((Math.ceil((contentX + width) / scale) - offsetF) / step);
                    for (var n = startN; n <= endN; n++) {
                        var f = offsetF + n * step;
                        var x = f * scale - contentX;
                        ctx.beginPath();
                        if (isBpm) {
                            var isMeasure = (n % (gridSettings.subdivision * bpmDiv) === 0);
                            var isBeat = (n % bpmDiv === 0);
                            if (isMeasure) {
                                ctx.strokeStyle = Qt.rgba(0.5, 0.8, 1, 0.5);
                                ctx.lineWidth = 1.5;
                            } else if (isBeat) {
                                ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.3);
                                ctx.lineWidth = 1;
                            } else {
                                ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.15);
                                ctx.lineWidth = 1;
                            }
                        } else {
                            ctx.strokeStyle = Qt.rgba(0.5, 0.5, 0.5, 0.15);
                            ctx.lineWidth = 1;
                        }
                        ctx.moveTo(x, 0);
                        ctx.lineTo(x, height);
                        ctx.stroke();
                    }
                }
            }

        }

        Repeater {
            model: TimelineBridge ? TimelineBridge.clips : []

            delegate: Item {
                id: clipDelegate

                property int resizeDraftStart: -1
                property int resizeDraftDuration: -1
                property double scale: TimelineBridge ? TimelineBridge.timelineScale : 1
                readonly property bool isSelected: TimelineBridge && TimelineBridge.selection && TimelineBridge.selection.selectedClipId === modelData.id
                readonly property bool isLayerLocked: getLayerLocked(modelData.layer)
                property int groupLayerCount: 0
                property var groupEffectModel: null
                property string clipDisplayName: modelData.type

                function updateGroupInfo() {
                    groupLayerCount = 0;
                    groupEffectModel = null;
                    if (!isSelected || !TimelineBridge)
                        return ;

                    var effects = TimelineBridge.getClipEffectsModel(modelData.id);
                    for (var i = 0; i < effects.length; i++) {
                        if (effects[i].id === "GroupControl") {
                            groupEffectModel = effects[i];
                            groupLayerCount = groupEffectModel.params["layerCount"] || 0;
                            break;
                        }
                    }
                }

                x: (resizeDraftStart >= 0 ? resizeDraftStart : modelData.startFrame) * scale
                y: modelData.layer * layerHeight
                width: (resizeDraftDuration >= 0 ? resizeDraftDuration : modelData.durationFrames) * scale
                height: layerHeight
                z: modelData.layer
                onIsSelectedChanged: updateGroupInfo()
                Component.onCompleted: updateGroupInfo()

                Connections {
                    function onClipEffectsChanged(clipId) {
                        if (clipId === modelData.id)
                            clipDelegate.updateGroupInfo();

                    }

                    target: TimelineBridge
                }

                Connections {
                    function onParamsChanged() {
                        if (clipDelegate.groupEffectModel)
                            clipDelegate.groupLayerCount = clipDelegate.groupEffectModel.params["layerCount"] || 0;

                    }

                    target: clipDelegate.groupEffectModel
                    ignoreUnknownSignals: true
                }

                Rectangle {
                    visible: clipDelegate.isSelected && clipDelegate.groupLayerCount > 0
                    x: 0
                    y: layerHeight
                    width: parent.width
                    height: clipDelegate.groupLayerCount * layerHeight
                    color: Qt.rgba(palette.highlight.r, palette.highlight.g, palette.highlight.b, 0.18)
                    border.color: Qt.rgba(palette.highlight.r, palette.highlight.g, palette.highlight.b, 0.55)
                    border.width: 1
                    z: -1
                }

                Rectangle {
                    id: clipRect

                    anchors.fill: parent
                    anchors.bottomMargin: 2
                    color: {
                        var c = TimelineBridge ? TimelineBridge.getClipTypeColor(modelData.type) : "";
                        if (c !== "")
                            return isSelected ? Qt.lighter(c, 1.3) : c;

                        return isSelected ? palette.highlight : palette.mid;
                    }
                    border.color: isSelected ? palette.highlight : palette.midlight
                    border.width: isSelected ? 2 : 1
                    opacity: 0.8
                    radius: 4

                    Text {
                        readonly property int padding: 4
                        property real stickyX: Math.max(0, timelineFlickable.contentX - clipDelegate.x)

                        anchors.verticalCenter: parent.verticalCenter
                        text: clipDelegate.clipDisplayName + " (" + modelData.id + ")"
                        color: "white"
                        font.pixelSize: 10
                        elide: Text.ElideRight
                        x: Math.min(stickyX, parent.width - width - padding) + padding
                        width: Math.min(implicitWidth, parent.width - padding * 2)
                    }

                    Canvas {
                        id: waveformCanvas

                        readonly property bool isAudio: modelData.type === "audio"
                        property int waveRev: 0
                        property bool _paintPending: false
                        readonly property int displayDuration: {
                            if (clipDelegate.resizeDraftDuration >= 0)
                                return clipDelegate.resizeDraftDuration;

                            return modelData.durationFrames;
                        }

                        function _schedulePaint() {
                            if (!isAudio)
                                return ;

                            if (_paintPending)
                                return ;

                            _paintPending = true;
                            Qt.callLater(function() {
                                _paintPending = false;
                                waveformCanvas.requestPaint();
                            });
                        }

                        anchors.fill: parent
                        visible: isAudio
                        opacity: 0.7
                        onWidthChanged: _schedulePaint()
                        onDisplayDurationChanged: _schedulePaint()
                        onWaveRevChanged: _schedulePaint()
                        onPaint: {
                            var ctx = getContext("2d");
                            ctx.clearRect(0, 0, width, height);
                            if (!isAudio || width <= 0 || !TimelineBridge)
                                return ;

                            var pw = Math.floor(width);
                            var dur = displayDuration;
                            if (pw <= 0 || dur <= 0)
                                return ;

                            var peaks = TimelineBridge.getWaveformPeaks(modelData.id, pw, dur);
                            if (!peaks || peaks.length === 0)
                                return ;

                            var cy = height / 2;
                            var maxH = cy - 2;
                            ctx.strokeStyle = "rgba(255, 255, 255, 0.9)";
                            ctx.lineWidth = 1;
                            for (var i = 0; i < peaks.length; i++) {
                                var h = Math.max(1, peaks[i] * maxH);
                                ctx.beginPath();
                                ctx.moveTo(i + 0.5, cy - h);
                                ctx.lineTo(i + 0.5, cy + h);
                                ctx.stroke();
                            }
                        }

                        Connections {
                            function onClipsChanged() {
                                waveformCanvas._schedulePaint();
                            }

                            target: TimelineBridge
                        }

                    }

                    MouseArea {
                        id: moveArea

                        property point dragStartScenePos: Qt.point(0, 0)
                        property int initialLayer: 0
                        property int initialFrame: 0
                        property int lastProposedFrame: -1
                        property int lastProposedLayer: -1

                        anchors.fill: parent
                        anchors.leftMargin: clipResizeHandleWidth
                        anchors.rightMargin: clipResizeHandleWidth
                        acceptedButtons: Qt.LeftButton | Qt.RightButton
                        cursorShape: clipDelegate.isLayerLocked ? Qt.ForbiddenCursor : Qt.OpenHandCursor
                        preventStealing: true
                        onPressed: (mouse) => {
                            if (clipDelegate.isLayerLocked)
                                return ;

                            if (TimelineBridge)
                                TimelineBridge.selectClip(modelData.id);

                            var sp = mapToItem(timelineFlickable.contentItem, mouse.x, mouse.y);
                            dragStartScenePos = sp;
                            initialLayer = modelData.layer;
                            initialFrame = modelData.startFrame;
                            lastProposedFrame = -1;
                            lastProposedLayer = -1;
                        }
                        onPositionChanged: (mouse) => {
                            if (!pressed || clipDelegate.isLayerLocked)
                                return ;

                            var sp = mapToItem(timelineFlickable.contentItem, mouse.x, mouse.y);
                            var dX = sp.x - dragStartScenePos.x;
                            var dY = sp.y - dragStartScenePos.y;
                            var rawF = initialFrame + dX / clipDelegate.scale;
                            var propF = timelineViewRoot.snapFrame(rawF);
                            var propL = Math.max(0, Math.min(initialLayer + Math.round(dY / layerHeight), timelineViewRoot.layerCount - 1));
                            propF = Math.max(0, propF);
                            if (propF === lastProposedFrame && propL === lastProposedLayer)
                                return ;

                            lastProposedFrame = propF;
                            lastProposedLayer = propL;
                            var finalF = propF, finalL = propL;
                            if (TimelineBridge && typeof TimelineBridge.resolveDragPosition === "function") {
                                var pos = TimelineBridge.resolveDragPosition(modelData.id, propL, propF);
                                finalF = pos.x;
                                finalL = pos.y;
                            }
                            if (finalF !== propF)
                                timelineFlickable.contentX = Math.max(0, timelineFlickable.contentX + (finalF - propF) * clipDelegate.scale);

                            clipDelegate.x = finalF * clipDelegate.scale;
                            clipDelegate.y = finalL * layerHeight;
                        }
                        onReleased: {
                            if (!TimelineBridge)
                                return ;

                            var newStart = Math.round(clipDelegate.x / clipDelegate.scale);
                            var newLayer = Math.round(clipDelegate.y / layerHeight);
                            TimelineBridge.updateClip(modelData.id, newLayer, newStart, modelData.durationFrames);
                            // バインディング復元 (ドラフトは使っていないので x/y のみ)
                            clipDelegate.x = Qt.binding(() => {
                                return (clipDelegate.resizeDraftStart >= 0 ? clipDelegate.resizeDraftStart : modelData.startFrame) * clipDelegate.scale;
                            });
                            clipDelegate.y = Qt.binding(() => {
                                return modelData.layer * layerHeight;
                            });
                        }
                        onDoubleClicked: {
                            if (WindowManager)
                                WindowManager.raiseWindow("objectSettings");

                        }
                        onClicked: (mouse) => {
                            if (mouse.button === Qt.RightButton) {
                                var frame = timelineViewRoot.snapFrame((clipDelegate.x + mouse.x) / clipDelegate.scale);
                                contextMenu.openAt(mouse.x, mouse.y, "clip", frame, modelData.layer, modelData.id);
                            }
                        }
                    }

                    Rectangle {
                        width: clipResizeHandleWidth
                        height: parent.height
                        anchors.left: parent.left
                        color: "transparent"
                        z: 10

                        MouseArea {
                            id: leftResizeArea

                            property real startSceneX: 0 // Flickable contentItem 座標
                            property int startFrame: 0
                            property int startDuration: 0
                            property bool resizing: false

                            anchors.fill: parent
                            cursorShape: Qt.SizeHorCursor
                            hoverEnabled: true
                            preventStealing: true
                            onPressed: (mouse) => {
                                if (clipDelegate.isLayerLocked)
                                    return ;

                                var sp = mapToItem(timelineFlickable.contentItem, mouse.x, mouse.y);
                                startSceneX = sp.x;
                                startFrame = modelData.startFrame;
                                startDuration = modelData.durationFrames;
                                resizing = true;
                                if (TimelineBridge)
                                    TimelineBridge.selectClip(modelData.id);

                                mouse.accepted = true;
                            }
                            onPositionChanged: (mouse) => {
                                if (!resizing)
                                    return ;

                                var sp = mapToItem(timelineFlickable.contentItem, mouse.x, mouse.y);
                                var delta = sp.x - startSceneX;
                                // 右端（終点）を固定して左端のみ動かす
                                var endFrame = startFrame + startDuration;
                                var rawNewStart = startFrame + delta / clipDelegate.scale;
                                var newStart = Math.max(0, timelineViewRoot.snapFrame(rawNewStart));
                                var newDur = endFrame - newStart;
                                var minDur = SettingsManager ? SettingsManager.value("minClipDurationFrames", 5) : 5;
                                if (newDur < minDur) {
                                    newStart = endFrame - 5;
                                    newDur = 5;
                                }
                                // ドラフトプロパティ経由で表示更新（バインディング破壊なし）
                                clipDelegate.resizeDraftStart = newStart;
                                clipDelegate.resizeDraftDuration = newDur;
                            }
                            onReleased: {
                                if (!resizing)
                                    return ;

                                resizing = false;
                                if (TimelineBridge && clipDelegate.resizeDraftDuration > 0)
                                    TimelineBridge.updateClip(modelData.id, modelData.layer, clipDelegate.resizeDraftStart >= 0 ? clipDelegate.resizeDraftStart : modelData.startFrame, clipDelegate.resizeDraftDuration);

                                // ドラフト解除 → バインディングが自動で正値を返す
                                clipDelegate.resizeDraftStart = -1;
                                clipDelegate.resizeDraftDuration = -1;
                            }
                        }

                    }

                    Rectangle {
                        width: clipResizeHandleWidth
                        height: parent.height
                        anchors.right: parent.right
                        color: "transparent"
                        z: 10

                        MouseArea {
                            id: rightResizeArea

                            property real startSceneX: 0 // Flickable contentItem 座標
                            property int startFrame: 0 // リサイズ開始時の startFrame
                            property int startDuration: 0
                            property bool resizing: false

                            anchors.fill: parent
                            cursorShape: Qt.SizeHorCursor
                            hoverEnabled: true
                            preventStealing: true
                            onPressed: (mouse) => {
                                if (clipDelegate.isLayerLocked)
                                    return ;

                                var sp = mapToItem(timelineFlickable.contentItem, mouse.x, mouse.y);
                                startSceneX = sp.x;
                                startFrame = modelData.startFrame;
                                startDuration = modelData.durationFrames;
                                resizing = true;
                                if (TimelineBridge)
                                    TimelineBridge.selectClip(modelData.id);

                                mouse.accepted = true;
                            }
                            onPositionChanged: (mouse) => {
                                if (!resizing)
                                    return ;

                                var sp = mapToItem(timelineFlickable.contentItem, mouse.x, mouse.y);
                                var delta = sp.x - startSceneX;
                                // 右端フレームをスナップ
                                var rawEndFrame = startFrame + (startDuration * clipDelegate.scale + delta) / clipDelegate.scale;
                                var snappedEndFrame = timelineViewRoot.snapFrame(rawEndFrame);
                                var minDur = SettingsManager ? SettingsManager.value("minClipDurationFrames", 5) : 5;
                                var newDur = Math.max(minDur, snappedEndFrame - startFrame);
                                // ドラフトプロパティ経由で表示更新（バインディング破壊なし）
                                clipDelegate.resizeDraftDuration = newDur;
                            }
                            onReleased: {
                                if (!resizing)
                                    return ;

                                resizing = false;
                                if (TimelineBridge && clipDelegate.resizeDraftDuration > 0)
                                    TimelineBridge.updateClip(modelData.id, modelData.layer, modelData.startFrame, clipDelegate.resizeDraftDuration);

                                // ドラフト解除 → バインディングが自動で正値を返す
                                clipDelegate.resizeDraftDuration = -1;
                            }
                        }

                    }

                }

            }

        }

        Rectangle {
            id: playhead

            x: (TimelineBridge && TimelineBridge.transport ? TimelineBridge.transport.currentFrame : 0) * (TimelineBridge ? TimelineBridge.timelineScale : 1)
            y: 0
            width: 2
            height: parent.height
            color: "red"
            z: 100
        }

        MouseArea {
            anchors.fill: parent
            z: -1
            acceptedButtons: Qt.LeftButton | Qt.RightButton
            onClicked: (mouse) => {
                var scale = TimelineBridge ? TimelineBridge.timelineScale : 1;
                var frame = timelineViewRoot.snapFrame(mouse.x / scale);
                if (mouse.button === Qt.LeftButton) {
                    if (TimelineBridge && TimelineBridge.transport)
                        TimelineBridge.transport.setCurrentFrame_seek(frame);

                } else {
                    var layer = Math.floor(mouse.y / layerHeight);
                    contextMenu.openAt(mouse.x, mouse.y, "timeline", frame, layer, -1);
                }
            }
        }

        MouseArea {
            anchors.fill: parent
            acceptedButtons: Qt.NoButton
            onWheel: (wheel) => {
                var dy = (wheel.pixelDelta && wheel.pixelDelta.y !== 0) ? wheel.pixelDelta.y * 10 : wheel.angleDelta.y;
                var dx = (wheel.pixelDelta && wheel.pixelDelta.x !== 0) ? wheel.pixelDelta.x * 10 : wheel.angleDelta.x;
                if (wheel.modifiers & Qt.ShiftModifier) {
                    var maxY = Math.max(0, timelineFlickable.contentHeight - timelineFlickable.height);
                    timelineFlickable.contentY = clamp(timelineFlickable.contentY - dy, 0, maxY);
                } else {
                    var delta = (Math.abs(dx) > Math.abs(dy)) ? dx : dy;
                    var maxX = Math.max(0, timelineFlickable.contentWidth - timelineFlickable.width);
                    timelineFlickable.contentX = clamp(timelineFlickable.contentX - delta, 0, maxX);
                }
                wheel.accepted = true;
            }
        }

    }

    Menu {
        id: contextMenu

        property string targetType: ""
        property int targetClipId: -1

        function openAt(x, y, type, frame, layer, clipId) {
            targetType = type;
            targetClipId = clipId;
            contextClickFrame = frame;
            contextClickLayer = layer;
            rebuildMenu();
            popup();
        }

        function createMenuItem(label, cmd, icon) {
            var item = menuItemComp.createObject(null, {
                "text": label,
                "iconName": icon || ""
            });
            item.triggered.connect(() => {
                return handleCommand(cmd);
            });
            return item;
        }

        function createSubMenu(label) {
            return subMenuComp.createObject(null, {
                "title": label
            });
        }

        function addSeparator() {
            contextMenu.addItem(menuSeparatorComp.createObject(null));
        }

        function handleCommand(cmd) {
            if (!TimelineBridge)
                return ;

            if (cmd.startsWith("add.")) {
                TimelineBridge.createObject(cmd.substring(4), contextClickFrame, contextClickLayer);
                return ;
            }
            switch (cmd) {
            case "edit.undo":
                TimelineBridge.undo();
                break;
            case "edit.redo":
                TimelineBridge.redo();
                break;
            case "clip.delete":
                TimelineBridge.deleteClip(targetClipId);
                break;
            case "clip.split":
                TimelineBridge.splitClip(targetClipId, contextClickFrame);
                break;
            case "clip.cut":
                TimelineBridge.cutClip(targetClipId);
                break;
            case "clip.copy":
                TimelineBridge.copyClip(targetClipId);
                break;
            case "edit.paste":
                TimelineBridge.pasteClip(contextClickFrame, contextClickLayer);
                break;
            case "view.gridsettings":
                gridSettingsRequested();
                break;
            default:
                console.log("Unknown command:", cmd);
            }
        }

        function rebuildMenu() {
            while (contextMenu.count > 0) {
                var item = contextMenu.itemAt(0);
                contextMenu.removeItem(item);
                (function(obj) {
                    Qt.callLater(() => {
                        try {
                            if (obj)
                                obj.destroy();

                        } catch (e) {
                        }
                    });
                })(item);
            }
            if (targetType === "timeline") {
                var objectMenu = createSubMenu("オブジェクトを追加");
                var objects = TimelineBridge.getAvailableObjects();
                for (var i = 0; i < objects.length; i++) {
                    var obj = objects[i];
                    var objItem = menuItemComp.createObject(null, {
                        "text": obj.name,
                        "iconName": "shape_line"
                    });
                    (function(id) {
                        objItem.triggered.connect(() => {
                            return handleCommand("add." + id);
                        });
                    })(obj.id);
                    objectMenu.addItem(objItem);
                }
                contextMenu.addMenu(objectMenu);
                addSeparator();
                contextMenu.addItem(createMenuItem("元に戻す", "edit.undo", "arrow_go_back_line"));
                contextMenu.addItem(createMenuItem("やり直す", "edit.redo", "arrow_go_forward_line"));
                contextMenu.addItem(createMenuItem("貼り付け", "edit.paste", "clipboard_line"));
                addSeparator();
                contextMenu.addItem(createMenuItem("グリッド設定...", "view.gridsettings", "grid_line"));
            } else if (targetType === "clip") {
                contextMenu.addItem(createMenuItem("削除", "clip.delete", "delete_bin_line"));
                contextMenu.addItem(createMenuItem("分割", "clip.split", "scissors_cut_line"));
                addSeparator();
                contextMenu.addItem(createMenuItem("切り取り", "clip.cut", "scissors_line"));
                contextMenu.addItem(createMenuItem("コピー", "clip.copy", "file_copy_line"));
            }
        }

        Component {
            id: menuItemComp

            Common.IconMenuItem {
            }

        }

        Component {
            id: subMenuComp

            Menu {
            }

        }

        Component {
            id: menuSeparatorComp

            MenuSeparator {
            }

        }

    }

}

