                border.color: startSwatchMa.containsMouse ? "#ffffff" : "#555555"
                border.width: 1
                ToolTip.visible: startSwatchMa.containsMouse
                ToolTip.text: colorRow._hasKf ? "開始色 (f" + colorRow._startFrame + ")" : "色を選択"

                MouseArea {
                    id: startSwatchMa

                    anchors.fill: parent
                    hoverEnabled: true
                    onClicked: {
                        var c = colorRow._startVal || "#ffffff";
