                                                    function bo(x) {
                                                        var n = 7.5625, d = 2.75;
                                                        if (x < 1 / d)
                                                            return n * x * x;

                                                        if (x < 2 / d) {
                                                            x -= 1.5 / d;
                                                            return n * x * x + 0.75;
                                                        }
                                                        if (x < 2.5 / d) {
                                                            x -= 2.25 / d;
                                                            return n * x * x + 0.9375;
                                                        }
                                                        x -= 2.625 / d;
                                                        return n * x * x + 0.984375;
                                                    }

                                                    // type = type.toLowerCase().replace(/_/g, ""); // キー名統一により不要
                                                    if (type === "linear")
                                                        return t;

                                                    if (type === "ease_in_quad")
                                                        return t * t;

                                                    if (type === "ease_out_quad")
                                                        return 1 - (1 - t) * (1 - t);

                                                    if (type === "ease_in_out_quad")
