                                                    if (type === "ease_out_in_cubic")
                                                        return t < 0.5 ? (1 - (1 - 2 * t) ** 3) / 2 : (2 * t - 1) ** 3 / 2 + 0.5;

                                                    if (type === "ease_in_quart")
                                                        return t ** 4;

                                                    if (type === "ease_out_quart")
                                                        return 1 - (1 - t) ** 4;

                                                    if (type === "ease_in_quint")
                                                        return t ** 5;

                                                    if (type === "ease_out_quint")
