import "Logger.js" as Logger
import QtQuick
import QtQuick3D

Node {
    id: loader

    property url source
    property var properties: ({
    })
    property QtObject item: null
    property int status: Loader.Null
    property string errorString: ""
    // 外部からコンポーネント取得関数を注入可能にする
    // function(url) -> Component
    property var componentFactory: null
    property Component _component: null

    function _load() {
        if (item) {
            item.destroy();
            item = null;
        }
        _component = null;
        status = Loader.Loading;
        errorString = "";
        if (source == "") {
            status = Loader.Null;
            return ;
        }
        var comp = null;
        if (componentFactory && typeof componentFactory === "function")
            comp = componentFactory(source);
        else
            comp = Qt.createComponent(source, Component.Asynchronous);
        _component = comp;
        _processStatus();
    }

    function _processStatus() {
        if (!_component)
            return ;

        status = _component.status;
        if (status === Component.Ready) {
            item = _component.createObject(loader, properties);
        } else if (status === Component.Error) {
            errorString = _component.errorString();
            Logger.log("[NodeLoader] コンポーネントエラー: " + errorString);
        }
    }

    onSourceChanged: _load()

    Connections {
        function onStatusChanged() {
            loader._processStatus();
        }

        target: _component
    }

}

import QtQuick

Item {
    id: renderer

    required property Item originalSource
    required property list<QtObject> effectModels
    required property int relFrame

    width:  originalSource ? originalSource.width  : 1
    height: originalSource ? originalSource.height : 1

    Item {
        id: fallbackItem
        width: 1; height: 1
        visible: true; opacity: 0.0
    }

    property alias output: textureSource
    readonly property Item finalItem: textureSource.sourceItem

    Repeater {
        id: effectChain
        model: renderer.effectModels

        Loader {
            id: effectLoader

            // rendererInstance のサイズに追従させ、item (BaseEffect) のサイズを確定させる
            anchors.fill: parent

            active: modelData.enabled
            source: modelData.qmlSource

            property Item inputSource: {
                if (index === 0) return renderer.originalSource;
                var prev = effectChain.itemAt(index - 1);
                if (prev && prev.status === Loader.Ready) return prev.item;
                return renderer.originalSource;
            }

            function _syncAll() {
                if (!item) return;
                if ("source"      in item) item.source      = inputSource;
                if ("params"      in item) item.params      = modelData.params;
                if ("effectModel" in item) item.effectModel = modelData;
                if ("frame"       in item) item.frame       = renderer.relFrame;
            }

            onLoaded:             _syncAll()
            onInputSourceChanged: {
                if (status === Loader.Ready) {
                    if ("source" in item) item.source = inputSource;
                }
            }

            Connections {
                target: renderer
                function onRelFrameChanged() {
                    if (effectLoader.status === Loader.Ready && effectLoader.item
                            && "frame" in effectLoader.item)
                        effectLoader.item.frame = renderer.relFrame;
                }
            }

            Connections {
                target: modelData
                function onParamsChanged() {
                    if (effectLoader.status === Loader.Ready && effectLoader.item
                            && "params" in effectLoader.item)
                        effectLoader.item.params = modelData.params;
                }
            }
        }
    }

    ShaderEffectSource {
        id: textureSource
        sourceItem: {
            if (!renderer.originalSource
                    || renderer.originalSource.width  <= 0
                    || renderer.originalSource.height <= 0)
                return fallbackItem;
            if (effectChain.count > 0)
                return findFinalOutput(renderer.originalSource);
            return renderer.originalSource;
        }
        visible:    false
        live:       true
        hideSource: true
        recursive:  false

        function findFinalOutput(defaultSource) {
            for (var i = effectChain.count - 1; i >= 0; i--) {
                var loader = effectChain.itemAt(i);
                // width/height チェックを除去: anchors.fill: parent で親に追従するため
                // サイズが 0 の場合は item が存在することだけを確認する
                if (loader && loader.status === Loader.Ready
                        && loader.active && loader.item)
                    return loader.item;
            }
            return defaultSource;
        }
    }
}

import QtQuick
